section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "title": "DjangoSelectorFunction",
  "type": "object",
  "required": ["name", "file", "kwarg_only", "return_type", "writes_db", "test_module"],
  "properties": {
    "name": { "type": "string", "pattern": "^[a-z][a-z0-9_]*$" },
    "file": { "type": "string", "pattern": ".+/selectors\\.py$" },
    "kwarg_only": { "const": true },
    "return_type": {
      "type": "string",
      "description": "QuerySet[<Model>] for list selectors, <Model> for single-object selectors"
    },
    "writes_db": { "const": false },
    "test_module": { "type": "string", "minLength": 1 }
  }
}

example.code:
from django.db.models import QuerySet, Prefetch
from apps.orders.models import Order, OrderItem


def order_list_for_user(*, user, status: str | None = None, limit: int | None = None) -> QuerySet[Order]:
    qs = (
        Order.objects.filter(user=user)
        .select_related("shipping_method")
        .prefetch_related(Prefetch("items", queryset=OrderItem.objects.select_related("product")))
        .order_by("-created_at")
    )
    if status:
        qs = qs.filter(status=status)
    if limit:
        qs = qs[:limit]
    return qs


def order_get_for_user(*, order_id: int, user) -> Order:
    return (
        Order.objects.select_related("user", "shipping_method")
        .prefetch_related("items__product")
        .filter(user=user)
        .get(pk=order_id)
    )

def order_list(user, status=None):                  # missing *: positional args
    return list(Order.objects.filter(user=user))    # returns list, not QuerySet

def order_get(order_id):
    try:
        return Order.objects.get(pk=order_id)
    except Order.DoesNotExist:
        return None                                  # MUST raise, not return None

def order_archive(*, order_id):                      # writes — should be in services.py
    Order.objects.filter(pk=order_id).update(archived=True)
